/**
 * Analytics service — aggregation and computation logic for the analytics dashboard.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture notes:
 * - This service reads from existing repositories; it does NOT write data.
 * - All methods return typed analytics models (see src/models/analytics.ts).
 * - Time-range filtering and granularity bucketing are the core operations.
 */

import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { Order } from '../models/order.js';
import type { User } from '../models/user.js';
import type {
  DashboardData,
  DashboardQuery,
  MetricQuery,
  MetricTimeSeriesResponse,
  BreakdownQuery,
  BreakdownResponse,
  MetricSummary,
  MetricType,
  TimeSeriesPoint,
  BreakdownItem,
  TimeGranularity,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard view with summary metrics, breakdowns, and trends.
   */
  getDashboard(query: DashboardQuery = {}): DashboardData {
    this.logger.info('Generating dashboard data');

    const endDate = query.endDate ?? new Date().toISOString();
    const startDate = query.startDate ?? new Date(new Date(endDate).getTime() - 30 * 24 * 60 * 60 * 1000).toISOString();

    const start = new Date(startDate);
    const end = new Date(endDate);
    const duration = end.getTime() - start.getTime();
    const prevStart = new Date(start.getTime() - duration);

    const currentOrders = this.getOrdersInRange(start, end);
    const previousOrders = this.getOrdersInRange(prevStart, start);
    const currentUsers = this.getUsersInRange(start, end);
    const previousUsers = this.getUsersInRange(prevStart, start);

    const metrics: MetricSummary[] = [
      this.computeMetricSummary('revenue', currentOrders, previousOrders, currentUsers, previousUsers),
      this.computeMetricSummary('orders', currentOrders, previousOrders, currentUsers, previousUsers),
      this.computeMetricSummary('users', currentOrders, previousOrders, currentUsers, previousUsers),
      this.computeMetricSummary('average-order-value', currentOrders, previousOrders, currentUsers, previousUsers),
    ];

    const ordersByStatus = this.computeStatusBreakdown(currentOrders);
    const recentOrdersTrend = this.buildOrderCountSeries(currentOrders, start, end, 'day');
    const revenueTrend = this.buildRevenueSeries(currentOrders, start, end, 'day');

    return {
      metrics,
      ordersByStatus,
      recentOrdersTrend,
      revenueTrend,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Get time series data for a single metric.
   */
  getMetricTimeSeries(query: MetricQuery): MetricTimeSeriesResponse {
    this.logger.info(`Generating time series for metric: ${query.metricType}`);

    const granularity = query.granularity ?? 'day';
    const start = new Date(query.startDate);
    const end = new Date(query.endDate);
    const duration = end.getTime() - start.getTime();
    const prevStart = new Date(start.getTime() - duration);

    const currentOrders = this.getOrdersInRange(start, end);
    const previousOrders = this.getOrdersInRange(prevStart, start);
    const currentUsers = this.getUsersInRange(start, end);
    const previousUsers = this.getUsersInRange(prevStart, start);

    const summary = this.computeMetricSummary(
      query.metricType, currentOrders, previousOrders, currentUsers, previousUsers,
    );

    let series: TimeSeriesPoint[];
    switch (query.metricType) {
      case 'revenue':
        series = this.buildRevenueSeries(currentOrders, start, end, granularity);
        break;
      case 'orders':
        series = this.buildOrderCountSeries(currentOrders, start, end, granularity);
        break;
      case 'users':
        series = this.buildUserCountSeries(currentUsers, start, end, granularity);
        break;
      case 'average-order-value':
        series = this.buildAovSeries(currentOrders, start, end, granularity);
        break;
    }

    return {
      metricType: query.metricType,
      summary,
      series,
      query: {
        startDate: query.startDate,
        endDate: query.endDate,
        granularity,
      },
    };
  }

  /**
   * Get a categorical breakdown (e.g., orders by status, by user, by product).
   */
  getBreakdown(query: BreakdownQuery): BreakdownResponse {
    this.logger.info(`Generating breakdown by: ${query.dimension}`);

    const endDate = query.endDate ?? new Date().toISOString();
    const startDate = query.startDate ?? new Date(new Date(endDate).getTime() - 30 * 24 * 60 * 60 * 1000).toISOString();
    const limit = query.limit ?? 10;

    const start = new Date(startDate);
    const end = new Date(endDate);
    const orders = this.getOrdersInRange(start, end);

    let items: BreakdownItem[];
    switch (query.dimension) {
      case 'status':
        items = this.computeStatusBreakdown(orders);
        break;
      case 'user':
        items = this.computeUserBreakdown(orders);
        break;
      case 'product':
        items = this.computeProductBreakdown(orders);
        break;
    }

    items = items.slice(0, limit);
    const total = items.reduce((sum, item) => sum + item.value, 0);

    return {
      dimension: query.dimension,
      items,
      total,
      query: {
        startDate,
        endDate,
        limit,
      },
    };
  }

  // --- Private helpers ---

  private getOrdersInRange(start: Date, end: Date): Order[] {
    return this.orderRepository.findAll(
      (order) => order.createdAt >= start && order.createdAt < end,
    );
  }

  private getUsersInRange(start: Date, end: Date): User[] {
    return this.userRepository.findAll(
      (user) => user.createdAt >= start && user.createdAt < end,
    );
  }

  private computeMetricSummary(
    metricType: MetricType,
    currentOrders: Order[],
    previousOrders: Order[],
    currentUsers: User[],
    previousUsers: User[],
  ): MetricSummary {
    let currentValue: number;
    let previousValue: number;

    switch (metricType) {
      case 'revenue':
        currentValue = currentOrders.reduce((sum, o) => sum + o.total, 0);
        previousValue = previousOrders.reduce((sum, o) => sum + o.total, 0);
        break;
      case 'orders':
        currentValue = currentOrders.length;
        previousValue = previousOrders.length;
        break;
      case 'users':
        currentValue = currentUsers.length;
        previousValue = previousUsers.length;
        break;
      case 'average-order-value':
        currentValue = currentOrders.length > 0
          ? currentOrders.reduce((sum, o) => sum + o.total, 0) / currentOrders.length
          : 0;
        previousValue = previousOrders.length > 0
          ? previousOrders.reduce((sum, o) => sum + o.total, 0) / previousOrders.length
          : 0;
        break;
    }

    const changePercent = previousValue !== 0
      ? ((currentValue - previousValue) / previousValue) * 100
      : currentValue > 0 ? 100 : 0;

    const trend: MetricSummary['trend'] =
      changePercent > 0 ? 'up' : changePercent < 0 ? 'down' : 'flat';

    const formattedValue = metricType === 'revenue' || metricType === 'average-order-value'
      ? `$${currentValue.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
      : String(currentValue);

    return {
      metricType,
      currentValue,
      previousValue,
      changePercent: Math.round(changePercent * 100) / 100,
      trend,
      formattedValue,
    };
  }

  private computeStatusBreakdown(orders: Order[]): BreakdownItem[] {
    const counts = new Map<string, number>();
    for (const order of orders) {
      counts.set(order.status, (counts.get(order.status) ?? 0) + 1);
    }
    const total = orders.length;
    const items: BreakdownItem[] = [];
    for (const [category, value] of counts) {
      items.push({
        category,
        value,
        percentage: total > 0 ? Math.round((value / total) * 10000) / 100 : 0,
      });
    }
    return items.sort((a, b) => b.value - a.value);
  }

  private computeUserBreakdown(orders: Order[]): BreakdownItem[] {
    const totals = new Map<string, number>();
    for (const order of orders) {
      totals.set(order.userId, (totals.get(order.userId) ?? 0) + order.total);
    }
    const grandTotal = orders.reduce((sum, o) => sum + o.total, 0);
    const items: BreakdownItem[] = [];
    for (const [userId, value] of totals) {
      const user = this.userRepository.findById(userId);
      items.push({
        category: user ? user.name : userId,
        value,
        percentage: grandTotal > 0 ? Math.round((value / grandTotal) * 10000) / 100 : 0,
      });
    }
    return items.sort((a, b) => b.value - a.value);
  }

  private computeProductBreakdown(orders: Order[]): BreakdownItem[] {
    const quantities = new Map<string, { name: string; quantity: number }>();
    for (const order of orders) {
      for (const item of order.items) {
        const existing = quantities.get(item.productId);
        if (existing) {
          existing.quantity += item.quantity;
        } else {
          quantities.set(item.productId, { name: item.name, quantity: item.quantity });
        }
      }
    }
    const totalQuantity = Array.from(quantities.values()).reduce((sum, p) => sum + p.quantity, 0);
    const items: BreakdownItem[] = [];
    for (const [, { name, quantity }] of quantities) {
      items.push({
        category: name,
        value: quantity,
        percentage: totalQuantity > 0 ? Math.round((quantity / totalQuantity) * 10000) / 100 : 0,
      });
    }
    return items.sort((a, b) => b.value - a.value);
  }

  /**
   * Generate time bucket boundaries between start and end for the given granularity.
   */
  private generateBuckets(start: Date, end: Date, granularity: TimeGranularity): Date[] {
    const buckets: Date[] = [];
    const current = new Date(start);

    // Align to bucket boundary
    switch (granularity) {
      case 'hour':
        current.setMinutes(0, 0, 0);
        break;
      case 'day':
        current.setHours(0, 0, 0, 0);
        break;
      case 'week': {
        current.setHours(0, 0, 0, 0);
        const dayOfWeek = current.getDay();
        current.setDate(current.getDate() - dayOfWeek);
        break;
      }
      case 'month':
        current.setHours(0, 0, 0, 0);
        current.setDate(1);
        break;
    }

    while (current < end) {
      buckets.push(new Date(current));
      switch (granularity) {
        case 'hour':
          current.setHours(current.getHours() + 1);
          break;
        case 'day':
          current.setDate(current.getDate() + 1);
          break;
        case 'week':
          current.setDate(current.getDate() + 7);
          break;
        case 'month':
          current.setMonth(current.getMonth() + 1);
          break;
      }
    }
    return buckets;
  }

  private getBucketKey(date: Date, granularity: TimeGranularity): string {
    switch (granularity) {
      case 'hour':
        return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}T${String(date.getHours()).padStart(2, '0')}`;
      case 'day':
        return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
      case 'week': {
        const d = new Date(date);
        d.setDate(d.getDate() - d.getDay());
        return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
      }
      case 'month':
        return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
    }
  }

  private buildRevenueSeries(orders: Order[], start: Date, end: Date, granularity: TimeGranularity): TimeSeriesPoint[] {
    const buckets = this.generateBuckets(start, end, granularity);
    const revenueMap = new Map<string, number>();

    for (const bucket of buckets) {
      revenueMap.set(this.getBucketKey(bucket, granularity), 0);
    }
    for (const order of orders) {
      const key = this.getBucketKey(order.createdAt, granularity);
      if (revenueMap.has(key)) {
        revenueMap.set(key, revenueMap.get(key)! + order.total);
      }
    }

    return buckets.map((bucket) => ({
      timestamp: bucket.toISOString(),
      value: revenueMap.get(this.getBucketKey(bucket, granularity)) ?? 0,
    }));
  }

  private buildOrderCountSeries(orders: Order[], start: Date, end: Date, granularity: TimeGranularity): TimeSeriesPoint[] {
    const buckets = this.generateBuckets(start, end, granularity);
    const countMap = new Map<string, number>();

    for (const bucket of buckets) {
      countMap.set(this.getBucketKey(bucket, granularity), 0);
    }
    for (const order of orders) {
      const key = this.getBucketKey(order.createdAt, granularity);
      if (countMap.has(key)) {
        countMap.set(key, countMap.get(key)! + 1);
      }
    }

    return buckets.map((bucket) => ({
      timestamp: bucket.toISOString(),
      value: countMap.get(this.getBucketKey(bucket, granularity)) ?? 0,
    }));
  }

  private buildUserCountSeries(users: User[], start: Date, end: Date, granularity: TimeGranularity): TimeSeriesPoint[] {
    const buckets = this.generateBuckets(start, end, granularity);
    const countMap = new Map<string, number>();

    for (const bucket of buckets) {
      countMap.set(this.getBucketKey(bucket, granularity), 0);
    }
    for (const user of users) {
      const key = this.getBucketKey(user.createdAt, granularity);
      if (countMap.has(key)) {
        countMap.set(key, countMap.get(key)! + 1);
      }
    }

    return buckets.map((bucket) => ({
      timestamp: bucket.toISOString(),
      value: countMap.get(this.getBucketKey(bucket, granularity)) ?? 0,
    }));
  }

  private buildAovSeries(orders: Order[], start: Date, end: Date, granularity: TimeGranularity): TimeSeriesPoint[] {
    const buckets = this.generateBuckets(start, end, granularity);
    const revenueMap = new Map<string, number>();
    const countMap = new Map<string, number>();

    for (const bucket of buckets) {
      const key = this.getBucketKey(bucket, granularity);
      revenueMap.set(key, 0);
      countMap.set(key, 0);
    }
    for (const order of orders) {
      const key = this.getBucketKey(order.createdAt, granularity);
      if (revenueMap.has(key)) {
        revenueMap.set(key, revenueMap.get(key)! + order.total);
        countMap.set(key, countMap.get(key)! + 1);
      }
    }

    return buckets.map((bucket) => {
      const key = this.getBucketKey(bucket, granularity);
      const revenue = revenueMap.get(key) ?? 0;
      const count = countMap.get(key) ?? 0;
      return {
        timestamp: bucket.toISOString(),
        value: count > 0 ? revenue / count : 0,
      };
    });
  }
}

